const PROVISION_INDEX=[{"id": "s1-1", "num": "§1.1", "name": "Right to Courts and Legal Remedy", "text": "Every person may seek legal remedy for any rights violation before an independent court. This right is self-executing: where the Legislature has not funded adequate legal aid, courts appoint counsel at public expense. Procedural costs may not be used to make the right to a remedy illusory."}, {"id": "s1-2", "num": "§1.2", "name": "Individual Sovereignty Floor", "text": "Every person possesses an inviolable sphere of personal sovereignty over their own life, body, and choices. Government authority operates outside this sphere. Where the boundary is disputed, the presumption runs in favour of individual liberty; government bears the burden of demonstrating constituti"}, {"id": "s1-3", "num": "§1.3", "name": "Prohibition of Torture and Cruel Treatment", "text": "Torture and cruel, inhuman, or degrading treatment are absolutely prohibited. No person within the Republic's jurisdiction may be subjected to any such treatment under any circumstances. This right is non-derogable under §1.26.b."}, {"id": "s1-4", "num": "§1.4", "name": "Prohibition of Slavery and Forced Labour", "text": "Slavery, involuntary servitude, and forced labour are absolutely prohibited. Lawfully imposed prison labour and compulsory military service under the terms established by statute do not constitute forced labour under this provision. This right is non-derogable under §1.26.b."}, {"id": "s1-5", "num": "§1.5", "name": "Civil and Political Liberties", "text": "Every person holds the rights of expression, thought, conscience, religion, association, assembly, petition, and movement. Government may regulate the time, place, and manner of expression and assembly for compelling public-order purposes, subject to strict scrutiny and without discriminating on the"}, {"id": "s1-6", "num": "§1.6", "name": "Equality and Non-Discrimination", "text": "Every person is equal before the law. Government may not discriminate on the basis of race, ethnicity, sex, sexual orientation, gender identity, religion, national origin, disability, age, or economic status in the provision of any governmental benefit, the imposition of any burden, or the applicati"}, {"id": "s1-7", "num": "§1.7", "name": "Bodily Sovereignty and Privacy", "text": "Every person holds sovereign authority over their own body. Medical decisions are the province of the individual and their chosen provider. The state may promote public health through information, licensing, and access; it may not compel medical decisions or penalise their exercise. Every person hol"}, {"id": "s1-8", "num": "§1.8", "name": "Property and Security of the Home", "text": "Every person holds the right to own property and to security in their home. The state may take private property for public use only upon payment of just compensation determined by independent process, not by the taking authority. The home may not be entered without the occupant's consent or prior in"}, {"id": "s1-9", "num": "§1.9", "name": "Democratic Participation and Family", "text": "Every citizen holds the right to vote, stand for office, and participate in the democratic processes of the Republic, subject to the eligibility requirements established in this constitution. Every person holds the right to marry and found a family, free from governmental discrimination on the basis"}, {"id": "s1-10", "num": "§1.10", "name": "Right to Bear Arms", "text": "The right to keep and bear arms for lawful purposes including self-defence is recognised. States may establish licensing and safety frameworks. No government may enact a categorical prohibition on the civilian ownership of arms. The Legislature and States may regulate the type, transfer, and carry o"}, {"id": "s1-12", "num": "§1.12", "name": "Habeas Corpus", "text": "Every person detained by public authority has the right to challenge that detention before an independent court. The detaining authority must produce the person and justify the detention within the period established by statute. No court may decline to hear a habeas corpus application. This right is"}, {"id": "s1-13", "num": "§1.13", "name": "Rights of the Accused and Fair Trial", "text": "Every person accused of a criminal offence holds: the right to be informed promptly of the charges; the right to counsel of their choosing, or to competent, adequately resourced counsel appointed at public expense where they cannot afford representation; the right to adequate time and means to prepa"}, {"id": "s1-16", "num": "§1.16", "name": "Right to a Public Trial", "text": "Every person accused of a criminal offence has the right to a public trial before an independent court. Proceedings may be held in camera only to the minimum extent necessary to protect a compelling interest identified in advance by the court; the existence of any proceeding may not be concealed. Th"}, {"id": "s1-19", "num": "§1.19", "name": "Freedom from Retroactive Criminal Law", "text": "No person may be convicted of an act that was not a criminal offence when committed, or subjected to a penalty greater than that applicable at the time of the offence. No criminal law may be applied retroactively to the disadvantage of the accused. This right is non-derogable under §1.26.b."}, {"id": "s1-20", "num": "§1.20", "name": "Double Jeopardy", "text": "No person may be tried or punished twice for the same offence following a final acquittal or conviction. The Legislature defines by statute the scope of this protection, including its application across jurisdictions."}, {"id": "s1-21", "num": "§1.21", "name": "Social Assistance Floor", "text": "Every Inhabitant is entitled to access the Republic's social state systems under Article X. No government may exclude any person from social assistance on the basis of the characteristics listed in §1.6. The Legislature establishes by statute the content and administration of social assistance, subj"}, {"id": "s1-22", "num": "§1.22", "name": "Education", "text": "Every child has the right to education adequate to enable full civic participation. The state must ensure this education is available and accessible. Parents hold the right to direct the education of their children within the framework of public educational standards. The Legislature establishes by "}, {"id": "s1-23", "num": "§1.23", "name": "Environmental Obligations", "text": "Government holds an obligation not to cause environmental harm to persons within its jurisdiction through its own actions or through the actions of those it licences. The Legislature establishes by statute the framework for environmental protection, and may not enact statutes that systematically per"}, {"id": "s1-27", "num": "§1.27", "name": "Right to Seek Asylum", "text": "Every person who reaches the Republic's jurisdiction has the right to claim asylum and have that claim determined by an independent process under §6.4. The manner of entry does not affect this right. An asylum seeker is an Inhabitant of the Republic from the date of claim and holds all rights in thi"}, {"id": "s1-28", "num": "§1.28", "name": "Non-Refoulement", "text": "No person within the Republic's jurisdiction may be returned, expelled, or extradited to any territory where they face genuine risk of persecution, torture, or deprivation of life. This protection applies regardless of the person's status, conduct, or the nature of the receiving territory's governme"}, {"id": "s1-26", "num": "§1.26", "name": "Emergency Derogation", "text": "No emergency — however severe — suspends the Individual Sovereignty Floor in full. Temporary derogation of certain rights is permitted only under the strict conditions of this section; the rights enumerated in §1.26.b may not be derogated under any circumstances."}, {"id": "s1-26-a", "num": "§1.26.a", "name": "Emergency Derogation — Declaration Requirements", "text": "Emergency derogation of Article I rights requires a precisely structured declaration specifying: the nature of the emergency, which rights are limited, the geographic scope, the duration, and the review mechanism. The specificity requirement prevents open-ended emergency licenses — the government mu"}, {"id": "s1-26-b", "num": "§1.26.b", "name": "Non-Derogable Rights", "text": "These six rights are absolute under any circumstances: the prohibition on torture (§1.3); slavery (§1.4); habeas corpus (§1.12); the right to a public trial (§1.16); no retroactive punishment (§1.19); and non-refoulement (§1.28). No emergency declaration, executive order, or legislative act may dero"}, {"id": "s1-26-c", "num": "§1.26.c", "name": "Inspectorate Continuity", "text": "The three Inspectorates continue to operate with full constitutional authority throughout any emergency — they cannot be suspended or have their mandate reduced by emergency declaration. Accountability infrastructure is precisely most important when emergency powers are active."}, {"id": "s1-26-d", "num": "§1.26.d", "name": "Automatic Expiry and Judicial Review", "text": "Emergency measures lapse automatically at the expiry of the Declaration. Judicial review of any emergency measure is available to any citizen at any time, and courts may rule during the emergency that a specific measure is unconstitutional."}, {"id": "s1-26-e", "num": "§1.26.e", "name": "No Permanent Emergency", "text": "No emergency measure may be made permanent by legislative act. Every emergency measure lapses automatically at the expiry of the Declaration unless re-enacted through the ordinary legislative process. The Legislature may not extend an emergency measure by re-declaration within 60 days of its expiry,"}, {"id": "s2-1", "num": "§2.1", "name": "The President — Domain and Term", "text": "The President holds enumerated authority over: military command and force employment; foreign affairs and treaty negotiation; intelligence; trade agreements subject to §2.4; and appointments within the presidential domain. Presidential authority is enumerated; the PM's authority is residual. The Pre"}, {"id": "s2-2", "num": "§2.2", "name": "Military Authorization Framework", "text": "The President may use military force in immediate response to an active or imminent attack on Republic territory, citizens abroad, or treaty allies. Beyond immediate response, all use of military force requires legislative authorization. The President must notify both chambers and the PM promptly up"}, {"id": "s2-3", "num": "§2.3", "name": "Presidential Intelligence and Veto", "text": "Intelligence: The President directs foreign intelligence. No intelligence operation may be conducted against Republic citizens within Republic territory on the President's authority; such operations require independent judicial authorisation. The EI reports any order authorising domestic intelligenc"}, {"id": "s2-4", "num": "§2.4", "name": "Presidential Domain Operations", "text": "Trade: The President negotiates and concludes trade agreements. PM written concurrence is required only for provisions imposing national treatment obligations within Republic territory, provisions requiring new domestic legislation, or provisions creating direct obligations on domestic persons. All "}, {"id": "s2-5", "num": "§2.5", "name": "The Prime Minister — Domestic Executive Domain", "text": "The PM holds residual executive authority over all functions not enumerated as Presidential. To be eligible, a person must have held citizenship for the period established by statute. The PM answers to the House through the confidence mechanism and does not require presidential confirmation for the "}, {"id": "s2-6", "num": "§2.6", "name": "PM Accountability and Formation", "text": "The PM is accountable to the House. The House may remove the PM only through a constructive vote of no confidence: a single vote that simultaneously removes the sitting PM and installs a named replacement, by absolute majority of full seated House membership. A confidence vote that does not name and"}, {"id": "s2-7", "num": "§2.7", "name": "PM Legislative Instruments", "text": "The PM holds two instruments for engaging the Legislature on enacted bills. Suspensive Veto: the PM may return any bill with a written statement of objection specifying constitutional, fiscal, or operational grounds. The statement is published to the NRS. The Legislature may override by 2/3 of both "}, {"id": "s2-8", "num": "§2.8", "name": "Duty of Refusal", "text": "No civil servant or military member may comply with an order from either executive that would require violation of any constitutional provision or statute. Refusal of such an order creates no civil or criminal liability and is no basis for dismissal or penalty. The refusing person may report the ord"}, {"id": "s2-9", "num": "§2.9", "name": "Presidential Succession and Incapacity", "text": "Full succession activates on Presidential death, resignation, removal, or certified permanent incapacity. Authority transfers in order: (1) Senate Speaker; (2) Senate Deputy Speaker; (3) most senior member of the Senate Armed Services Committee. A successor serves the remainder of the current presid"}, {"id": "s2-10", "num": "§2.10", "name": "Executive Transparency", "text": "Both executives must publish all official acts — orders, certifications, vetoes, objections, determinations, and refusals to certify — to the NRS within the period defined by statute. No executive may classify, delay, or suppress publication of an act this constitution requires to be published. Acts"}, {"id": "s2-11", "num": "§2.11", "name": "Emergency Governance", "text": "Where the House is unable to function for an extended period — as defined by statute — the Senate may assume joint emergency legislative authority for three functions only: election administration, social state funding continuity, and active national security obligations. All Senate emergency action"}, {"id": "s2-12", "num": "§2.12", "name": "Clemency", "text": "Each executive holds clemency authority within their own domain only. Presidential clemency covers military law and national security offenses. PM clemency covers domestic offenses. Neither may pardon offenses within the other's domain. Self-clemency is absolutely prohibited for all constitutional o"}, {"id": "s2-13", "num": "§2.13", "name": "Presidential Removal", "text": "The President may be removed on two independent tracks. Legislative track: 2/3 of both chambers simultaneously, following joint LI and EI certification of constitutional breach, demonstrated permanent incapacity, or conviction for a disqualifying offense. Popular track: a Senate majority may refer t"}, {"id": "s2-14", "num": "§2.14", "name": "Joint Executive Council", "text": "The Joint Executive Council comprises the President's domain officers and the PM's Cabinet ministers meeting jointly as a standing cross-executive coordination body. The Council is the primary forum for matters that cross executive domains. Both executives must attend at least one session per quarte"}, {"id": "s2-15", "num": "§2.15", "name": "Constitutional Continuity", "text": "Where a conflict between constitutional actors creates a risk of suspension of lawful governance or constitutionally mandated essential services, the applicable constitutional default is continuity of lawful governance at existing scope, pending formal resolution. No constitutional actor may use a r"}, {"id": "s3-1", "num": "§3.1", "name": "The Legislature", "text": "The Legislature comprises two chambers: the House of Representatives and the Senate. All legislation originates in the House. The Senate reviews, may amend within the subject matter of the bill, and must act on every House-passed bill within the period defined by statute — inaction triggers automati"}, {"id": "s3-2", "num": "§3.2", "name": "The House of Representatives", "text": "The House is the proportionally elected chamber. Both States and Territories send voting members; there are no second-class members. Seats are allocated by the Webster method based on population, with a minimum of one seat per State and Territory. The constituency divisor is established and may be a"}, {"id": "s3-3", "num": "§3.3", "name": "Electoral Districts", "text": "States draw their own House district maps subject to five criteria: population equality within reasonable tolerance; geographic contiguity; compliance with §1.6 non-discrimination; no intentional dilution of minority voting power; and reasonable compactness. Maps may not be drawn using partisan regi"}, {"id": "s3-4", "num": "§3.4", "name": "Legislative Standards", "text": "Single-subject rule: every bill must address a single, clearly defined subject. A court finding that a bill addresses multiple unrelated subjects voids the act. Bill exposure: the full text of every bill must be published to the NRS for a minimum period defined by statute before any final passage vo"}, {"id": "s3-5", "num": "§3.5", "name": "The Senate", "text": "The Senate comprises two senators per State regardless of population, elected for six-year staggered terms. No senator may serve more than two consecutive terms without sitting out one full term; no cumulative lifetime restriction applies after the cooling-off period. The Senate Speaker is elected b"}, {"id": "s3-6", "num": "§3.6", "name": "Treaty Ratification and Withdrawal", "text": "Treaty ratification requires 2/3 of the full seated Senate. Where a treaty fails ratification, standalone domestic provisions may be transmitted to the House as ordinary legislation unless the treaty is bilateral and its obligations are interdependent, in which case it must be renegotiated or abando"}, {"id": "s3-7", "num": "§3.7", "name": "Legislative Process and Passage", "text": "Bills pass by absolute majority of the full seated membership of both chambers. Higher thresholds apply to constitutional amendments, veto overrides, removal proceedings, and other matters specified in this constitution. The presiding officer of each chamber must publish the final text of every enac"}, {"id": "s3-8", "num": "§3.8", "name": "Legislative Oversight", "text": "All three Inspectorates have full access to legislative records, committee deliberations, voting records, and draft legislation; the Legislature may not withhold records from the Inspectorates. The LI publishes a constitutional compliance analysis of any enacted law during the legislative review per"}, {"id": "s3-9", "num": "§3.9", "name": "Independent Statutory Agencies", "text": "The Legislature may establish statutory agencies operating independently of both executives. Where this constitution assigns a function to a statutory agency, the Legislature must establish it; the relevant Inspectorate administers the function on an interim basis until the agency is established. Ag"}, {"id": "s3-10", "num": "§3.10", "name": "Impeachment", "text": "The House may impeach officers serving in the presidential executive domain and inferior court judges. The President is removed exclusively under §2.13; the PM under §2.6; SC justices under §4.2; legislative members by their own chamber. A 1/3 House minority may open an inquiry; full impeachment req"}, {"id": "s4-1", "num": "§4.1", "name": "Court Structure", "text": "The Republic's judiciary operates at three levels: district courts, appellate courts, and the Supreme Court. The House may establish, abolish, and define the jurisdiction of inferior courts by statute. States may maintain specialised court structures; any constitutional question arising in any proce"}, {"id": "s4-2", "num": "§4.2", "name": "Judicial Appointments and Independence", "text": "The PM nominates inferior court judges from a pool of qualified candidates maintained by the Elections Panel. The Legislature defines qualifications for inferior court judges by statute; the JI certifies eligibility of each pool applicant against those qualifications. The PM must nominate within the"}, {"id": "s4-3", "num": "§4.3", "name": "The Supreme Court", "text": "The Supreme Court consists initially of nine justices organised into three staggered classes, each serving a single non-renewable 12-year term. The Legislature may increase the number of justices by statute requiring 2/3 of both chambers; any seat added must be filled within 18 months or expires by operation of law. The "}, {"id": "s4-4", "num": "§4.4", "name": "Supreme Court Selection", "text": "SC justices are nominated by the PM from the open SC Candidate Registry maintained by the Elections Panel under §8.4.e — any eligible citizen who applies and meets the qualification criteria is entered. The PM nominates within the period defined by statute following a vacancy (not to exceed 90 days "}, {"id": "s4-5", "num": "§4.5", "name": "Judicial Review and Scope", "text": "Courts have authority to declare legislative acts, executive orders, and administrative decisions unconstitutional and void. No political actor may override a constitutional ruling. The SC identifies the constitutional defect; the Legislature may respond by enacting legislation that addresses it. Co"}, {"id": "s4-6", "num": "§4.6", "name": "Judgment Recognition", "text": "Judicial judgments, official records, and authenticated documents are recognised across all jurisdictions within the Republic. A judgment valid in one jurisdiction must be recognised in all others. Non-recognition grounds are exhaustive: the issuing court lacked jurisdiction; the judgment was obtain"}, {"id": "s4-7", "num": "§4.7", "name": "Jury Service", "text": "Citizens are required to serve on juries when called. Jury service is compensated at a rate the Legislature defines by statute. Unexcused refusal is subject to civil consequences the Legislature defines. Jury service does not constitute forced labour under §1.4."}, {"id": "s5-1", "num": "§5.1", "name": "Citizenship", "text": "Citizenship is acquired by birth, by parentage, or by naturalization. A child is automatically a citizen if at least one parent is a citizen or legal resident at birth. Children of citizens are Inhabitants from birth with full Article I protections; full citizenship rights activate at 18. Where a ch"}, {"id": "s5-1-c", "num": "§5.1.c", "name": "Naturalization and Service Path", "text": "A legal resident may earn citizenship after the continuous residency period and clean legal record established by statute, upon passing the Constitutional Logic Test (CLT). A legal resident may alternatively earn citizenship through honorable completion of military or national service. The CLT tests"}, {"id": "s5-1-f", "num": "§5.1.f", "name": "Derivative and Founding Status", "text": "A child born before a parent acquired legal residency or citizenship, who accompanies that parent to the Republic within a Legislature-defined window, receives derivative status. All individuals holding voting rights on Day Zero of ratification are automatically granted full citizenship as founding "}, {"id": "s5-2", "num": "§5.2", "name": "Legal Resident Rights", "text": "Legal residents hold a Residency Credential allowing them to work, enter contracts, own property, and access social state systems under Article X. They hold all Article I rights as Inhabitants. They do not hold federal voting rights or the right to stand for federal office. No child of a citizen or "}, {"id": "s5-3", "num": "§5.3", "name": "Custodial Care of Citizen Children", "text": "Where a parent or guardian who is the primary caregiver of a citizen child is removed from the Republic, the Republic accepts responsibility for that citizen child — housing, care, and connection to remaining family. The Republic may not separate citizen children from their sole caregivers without p"}, {"id": "s6-1", "num": "§6.1", "name": "The Dual-Gate System", "text": "Every immigration application must clear two sequential gates: Gate 1 (State sponsorship) and Gate 2 (federal certification). Legal residency requires passing both gates. States retain discretion over whom they sponsor but may not apply sponsorship criteria that violate §1.6. Federal certification c"}, {"id": "s6-2", "num": "§6.2", "name": "Enforcement, Removal, and Appeals", "text": "Only the federal government may remove individuals from the Republic. Removal occurs only for violations of laws the Legislature has defined — executive detention without statutory basis is unlawful detention subject to habeas corpus. Gate 2 denials are judicially challengeable on three grounds: cri"}, {"id": "s6-4", "num": "§6.4", "name": "Asylum and Protection", "text": "Asylum proceedings operate on a separate constitutional track from the dual-gate system. Any person who files an asylum claim under §1.28 is an Inhabitant from the date of filing — entitled to Article I protections and social state access. Claims must be determined before any removal order takes eff"}, {"id": "s6-4-c", "num": "§6.4.c", "name": "Asylum Court", "text": "The Asylum Court is a federal judicial institution constitutionally independent of both executive branches. Its judges are appointed under §4.2 and hold full tenure protections. The Legislature may not establish any asylum determination body as a subdivision or instrumentality of either executive br"}, {"id": "s6-4-e", "num": "§6.4.e", "name": "Unresolvable and Security Cases", "text": "The Legislature must define a minimum status, material conditions, and periodic judicial review for persons subject to final removal orders that cannot be executed — because the destination country will not accept them or execution would violate §1.28. Indefinite stateless detention is constitutiona"}, {"id": "s6-4-h", "num": "§6.4.h", "name": "Unaccompanied Minors", "text": "An unaccompanied minor arriving in the Republic is an Inhabitant from the moment of contact and holds full §1.28 protection. A federal legal guardian must be appointed within 24 hours. No unaccompanied minor may be detained in a facility not specifically designated and resourced for children."}, {"id": "s7-1", "num": "§7.1", "name": "The Right to Vote", "text": "Every eligible citizen holds the right to vote in federal elections and the right to have that vote counted. Government at every level is prohibited from taking any action that makes voting more difficult, less accessible, or less secure. No law, rule, administrative decision, or practice that reduc"}, {"id": "s7-2", "num": "§7.2", "name": "Presidential Election System", "text": "The President is elected through two concurrent requirements: a national RCV majority and a State plurality qualification. A candidate wins outright by satisfying both. Where a candidate's national RCV majority reaches or exceeds 60% of active ballots, the State plurality requirement is waived. Where no candid"}, {"id": "s7-2-b", "num": "§7.2.b", "name": "State Plurality Requirement", "text": "A candidate satisfies the State plurality requirement by receiving more first-preference votes than any other candidate in a majority of the Republic's States. The Elections Panel certifies State-by-State first-preference results as part of overall election certification. Certification is final and "}, {"id": "s7-3", "num": "§7.3", "name": "Federal Elections", "text": "Federal elections are held at regular intervals: House elections every two years; Senate elections on the staggered six-year cycle; presidential elections every four years. All federal elections use Ranked Choice Voting — majority required, not plurality — except the presidential election which foll"}, {"id": "s8-1", "num": "§8.1", "name": "Three Inspectorates", "text": "The Republic maintains three constitutionally independent Inspectorates — Legislative (LI), Executive (EI), and Judicial (JI) — each selected by bodies other than those it oversees. The Inspectorates hold an information-only mandate: they publish findings but do not issue binding orders. Each Inspec"}, {"id": "s8-1-a", "num": "§8.1.a", "name": "The Legislative Inspectorate", "text": "The LI audits the Legislature for fiscal accuracy, constitutional compliance. Responsibilities include: auditing the population census for constitutional compliance; reviewing House district maps against §3.3 criteria and publishing germaneness analyses; determining referendum eligibility; certifyin"}, {"id": "s8-1-b", "num": "§8.1.b", "name": "The Executive Inspectorate", "text": "The EI audits both executives and the Monetary Authority. Annual responsibilities include: military compliance assessment covering whether tier authorisations were followed, whether the §2.3 intelligence warrant requirement was maintained, and whether fund certifications were observed; publishing cl"}, {"id": "s8-1-c", "num": "§8.1.c", "name": "The Judicial Inspectorate", "text": "The JI audits the courts for judicial scope and independence. The JI certifies eligibility for the SC Candidate Registry under §8.4.e and confirms registry status for SC nominees, and conducts annual audits of the Elections Panel for electoral integrity compliance. The JI reviews accommodation compa"}, {"id": "s8-2", "num": "§8.2", "name": "Selection and Independence", "text": "Each Inspectorate is constituted through a process that structurally excludes the body being watched from selecting its watchers. The SC nominates the LI Inspector General, confirmed by national popular vote — the Legislature and both executives are entirely excluded. The House nominates the EI Inspector General, con"}, {"id": "s8-3", "num": "§8.3", "name": "Inspector General Selection", "text": "LI IG: nominated by the SC from a pool of qualified candidates maintained by the Elections Panel; confirmed by national popular vote at the next the federal electoral period following nomination, by simple majority of votes cast. The nominee takes office in an acting capacity immediately on nominati"}, {"id": "s8-4", "num": "§8.4", "name": "JI Audit and Certification Mandate", "text": "The JI holds two constitutional mandates: as auditor, it monitors the court system, certifies eligibility for the SC Candidate Registry maintained by the Elections Panel, and conducts compliance audits across compact obligations; as certification administrator, it certifies lottery draws and panel s"}, {"id": "s8-4-a", "num": "§8.4.a", "name": "Judicial IG Candidate Pool", "text": "The Elections Panel of the Digital Infrastructure Commission maintains the JI Candidate Pool. Eligibility is limited to former Republic judges — persons who have completed judicial service on a court of record at the trial court level or above, whether in a State court or the Republic's federal cour"}, {"id": "s8-4-e", "num": "§8.4.e", "name": "Supreme Court Candidate Registry", "text": "The Elections Panel of the Digital Infrastructure Commission maintains the standing SC Candidate Registry. Any citizen meeting the eligibility criteria — at least 15 years of legal practice or 10 years of judicial service, no current government position, no disqualifying financial interest — may app"}, {"id": "s8-5", "num": "§8.5", "name": "Inspector General Removal", "text": "For-cause removal of any IG requires: a substantiated finding from a State Designee Panel under §8.9; a 14-day SC appeal window from publication of the finding; and a 2/3 vote of both chambers simultaneously. Duty suspension triggers upon publication of a substantiated Panel finding, pending the vot"}, {"id": "s8-6", "num": "§8.6", "name": "Inspectorate Operations", "text": "The Inspectorates publish findings; they do not issue binding orders or legal determinations. Every finding, report, and discrepancy notice must be published to the NRS permanently and free of charge; no official may suppress, delay, classify, or alter an Inspectorate report before publication. Insp"}, {"id": "s8-7", "num": "§8.7", "name": "Triggered Investigations", "text": "The EI may investigate a constitutional officer for dereliction — failure to perform a constitutionally mandated function within the required period where that failure was not caused by circumstances genuinely beyond the officer's control. Political disagreement with a constitutional requirement is "}, {"id": "s8-8", "num": "§8.8", "name": "EI Annual Military Assessment", "text": "A dedicated section within the EI's annual report covers: whether military operations in the prior year were authorised through the correct tier; whether the §2.3 intelligence warrant requirement was maintained throughout all operations; whether PM fund certifications were obtained and observed; and"}, {"id": "s8-9", "num": "§8.9", "name": "Removal Grounds Review", "text": "The State Designee Panel is constituted per proceeding to determine, before any qualifying for-cause removal vote, whether the stated grounds are substantiated within the enumerated constitutional categories for the relevant office. The Panel publishes a binary finding only — grounds substantiated o"}, {"id": "s8-10", "num": "§8.10", "name": "Inspectorate Minimum Funding Guarantee", "text": "The annual appropriation for each Inspectorate may not fall below the prior fiscal year's funding level without a 2/3 vote of both chambers simultaneously. The Monetary Authority certifies each Inspectorate's prior-year funding level annually and publishes the certified floor to the NRS before the L"}, {"id": "s8-11", "num": "§8.11", "name": "Eight-Year Assessment", "text": "Every eight years from the date of full constitutional operation, the three Inspectorates jointly assess constitutional framework performance across: Article I rights enforcement across all jurisdictions; Inspectorate functioning and mandate adequacy; social state obligation compliance including hea"}, {"id": "s8-12", "num": "§8.12", "name": "Joint Inspectorate Council", "text": "The three Inspector Generals jointly constitute the JIC as the standing coordination body for matters crossing Inspectorate jurisdictions. The JIC formally houses all jointly certified constitutional functions — including the Eight-Year Assessment, lottery draws, and selection processes throughout t"}, {"id": "s8-13", "num": "§8.13", "name": "Constitutional Pool Framework", "text": "The Elections Panel of the Digital Infrastructure Commission maintains all constitutional candidate registries and pools as the administrative keeper of record. The Elections Panel receives applications, stores records, provides public access via the NRS, and enters certified applicants into the rel"}, {"id": "s9-1", "num": "§9.1", "name": "National Record System", "text": "The National Record System is the permanent, tamper-evident public record of the Republic — freely accessible to every Inhabitant at no cost. Every government act required to be published must appear on the NRS before it takes legal effect. Records may not be deleted, altered, or reclassified after "}, {"id": "s9-3", "num": "§9.3", "name": "Digital Infrastructure Advisory Council", "text": "The NRS and NVS are reviewed decennially by the Digital Infrastructure Advisory Council — an independent expert body that publishes advisory findings and recommendations to the Digital Infrastructure Commission. The Council convenes every ten years from the date of the first Legislature convening; t"}, {"id": "s9-4", "num": "§9.4", "name": "NRS and Electoral Integrity", "text": "All electoral records — voter registration, ballot counts, audit trails, certification documents — must be published to the NRS within the timeframes specified by the Elections Panel's constitutional mandate under Article XVI. No classification exception applies to electoral records."}, {"id": "s10-1", "num": "§10.1", "name": "The Social State and Monetary Authority", "text": "The Republic is a social state. Every Inhabitant is entitled to conditions of life consistent with human dignity, which the Republic fulfils through: universally accessible healthcare insurance; social assistance sufficient to maintain basic material conditions; and free compulsory education for eve"}, {"id": "s10-2", "num": "§10.2", "name": "Fiscal Accountability", "text": "The Legislature must pass a balanced budget or publish a structural deficit justification reviewed by the MA for fiscal accuracy. Structural deficits above the threshold defined by the MA require a published plan for return to balance. Where discretionary government spending is suspended due to budg"}, {"id": "s10-3", "num": "§10.3", "name": "Public Campaign Financing", "text": "The Legislature must establish a public campaign financing system within the period defined by statute following the first Legislature convening; failure to do so is a constitutional compliance breach certified by the LI. The system must provide all registered candidates with equal access to public "}, {"id": "s10-5", "num": "§10.5", "name": "Ethics and Conflict of Interest", "text": "All constitutional officers must disclose all financial interests, holdings, income sources, and liabilities to the EI within the period defined by statute of taking office and annually thereafter; disclosure records are published to the NRS. Any officer with a direct financial interest in a decisio"}, {"id": "s10-6", "num": "§10.6", "name": "National Endowment", "text": "The National Endowment is a constitutionally established reserve fund that backstops the Republic's social state obligations under §10.1 during periods of Severe Revenue Contraction, as certified by the independent Monetary Authority established under §10.1. It operates independently of the annual b"}, {"id": "s10-7", "num": "§10.7", "name": "Compensation of Public Officials", "text": "No government official may set their own compensation or the compensation of their direct supervisors. All official compensation is set by House statute and is a public record on the NRS. Official benefits and accommodations beyond compensation reflect the functional requirements of the office, not "}, {"id": "s11-1", "num": "§11.1", "name": "Optional Referendum", "text": "Citizens may initiate a national referendum to repeal enacted legislation by petition of 5% of eligible voters within 90 days of enactment. Laws that solely or primarily expand an Article I right, budget laws, and laws implementing a constitutionally mandated obligation are ineligible — the LI publi"}, {"id": "s11-2", "num": "§11.2", "name": "Citizen Legislative Initiative", "text": "Citizens may propose legislation directly to the Legislature by petition of 10% of eligible voters. The Legislature must vote on the proposal within 90 days; if it fails or is not voted on, the proposal proceeds to a national referendum at the §15.1 Path C thresholds. Citizen-initiated legislation t"}, {"id": "s11-3", "num": "§11.3", "name": "Local Government", "text": "Local governments — cities, counties, municipalities, and other subdivisions — receive constitutional recognition as primary points of contact between citizens and government. They are entitled to reasonable fiscal capacity to carry out their constitutional functions. States may not starve local gov"}, {"id": "s12-1", "num": "§12.1", "name": "Authorized Purposes for Military Force", "text": "Military force serves two authorized purposes: protection of the Republic's territory, citizens, and treaty allies; and, with legislative authorization stating the specific grounds, response to genocide. Three purposes are explicitly prohibited regardless of legislative authorization: nation-buildin"}, {"id": "s12-2", "num": "§12.2", "name": "Defense Authorization and Allocation", "text": "Military expenditure is authorized through PM certification concurrent with legislative authorization. No military operation may be funded without PM certification; the PM may certify, condition, or decline certification on any operation. Expenditure in categories not covered by the certification re"}, {"id": "s12-3", "num": "§12.3", "name": "Military Intelligence Operations", "text": "Intelligence capabilities used in support of authorized military operations are subject to the §2.3 warrant requirement at all times — no military operation authorizes domestic intelligence collection against citizens without independent judicial authorisation. Intelligence activities must be publis"}, {"id": "s12-4", "num": "§12.4", "name": "Military Accountability", "text": "Within 90 days of legislative military authorization being renewed for a second time, the Senate must approve a Transition and Reconstruction Plan specifying the Republic's post-conflict obligations: status of alliance obligations, civilian reconstruction support, transitional justice support, and w"}, {"id": "s12-5", "num": "§12.5", "name": "Treaty-Based Military Authorization", "text": "Where an existing treaty requires emergency military action, the President may act immediately and must notify both chambers and the PM within 12 hours, citing the specific treaty obligation triggered. The legislature must then authorize continuation within the period defined by statute; absent auth"}, {"id": "s13-1", "num": "§13.1", "name": "Territorial Compact", "text": "A Territory operates under a Territorial Compact, has federal protections under Article I, accesses social state systems under §10.1, and may begin the Statehood pathway under §13.2. Territories hold House seats proportional to their population and participate as full voting members. Territories do "}, {"id": "s13-2", "num": "§13.2", "name": "The Statehood Audit", "text": "The pathway from Territory to State is automatic upon passing the Statehood Audit and Provisional Membership Period — no political vote is required once the audit is passed. The audit has two components: the LI audits fiscal integrity; the JI audits legal compliance with every Article I right. Both "}, {"id": "s13-3", "num": "§13.3", "name": "Mandatory Devolution", "text": "A State enters Mandatory Devolution if it fails three consecutive annual Statehood Audits, certified by the LI and confirmed by both the EI and JI. After each failing audit, the LI publishes an Early Warning specifying compliance requirements; the State must publish a Remediation Plan within 60 days"}, {"id": "s13-4", "num": "§13.4", "name": "Voluntary Devolution and Merger", "text": "A State may voluntarily restructure its relationship with the Republic. The process requires: a State referendum achieving 60% approval of eligible voters on the specific proposed restructuring; and Senate approval of a negotiated restructuring agreement by 2/3 majority. The agreement specifies asse"}, {"id": "s13-5", "num": "§13.5", "name": "Re-Qualification Pathway", "text": "A Territory resulting from mandatory or voluntary devolution enters the Statehood re-qualification pathway under §13.2 immediately upon the effective date of devolution. No additional political vote is required to begin the pathway."}, {"id": "s13-6", "num": "§13.6", "name": "Voluntary Incorporation", "text": "A sovereign entity may petition to join the Republic's constitutional framework as a Territory. The process requires: a petition resolution adopted by the entity's own legislature by 2/3 majority, confirmed by a citizen referendum achieving simple majority on at least 50% participation; the JI's pub"}, {"id": "s13-7", "num": "§13.7", "name": "State Immutability and Territorial Integrity", "text": "A State's constitutional boundaries are fixed. No constitutional mechanism permits a State to divide directly into two or more States — the separating portion must first become a Territory before seeking independent Statehood. The Republic's territorial extent may only be reduced by the consent of t"}, {"id": "s14-1", "num": "§14.1", "name": "Acknowledgment of Prior Sovereignty", "text": "The foundational provision recognizing that Indigenous Nations within the Republic's territory hold a distinct constitutional relationship based on prior sovereignty. The compact relationship is bilateral: the Republic acknowledges Indigenous prior sovereignty; Indigenous Nations acknowledge the Rep"}, {"id": "s14-2", "num": "§14.2", "name": "Compact Formation", "text": "An Indigenous Nation may enter a compact with the Republic by submitting a compact proposal to the Senate. The Senate must within 90 days either begin compact negotiations or publish written reasons for declining; a declined proposal may be resubmitted after 5 years or after a material change in cir"}, {"id": "s14-3", "num": "§14.3", "name": "Rights and Governance in Compact Territories", "text": "Article I rights apply in full within all compact territories; no compact provision may limit or qualify any Article I right; where compact governance conflicts with an Article I right, Article I prevails. Indigenous Nations with compacts hold governance, judicial, and resource sovereignty within th"}, {"id": "s14-4", "num": "§14.4", "name": "Compact Administration and Continuity", "text": "Compacts are living agreements administered through joint mechanisms. Disputes are resolved through a Joint Compact Review Council with equal representation of the Nation and the Republic. The Republic is represented on the Council by the PM's designated Compact Officer for domestic and governance m"}, {"id": "s14-5", "num": "§14.5", "name": "Federal Obligations and New Compact Petitions", "text": "The Republic holds affirmative obligations to compact territories: federal education funding, healthcare access, infrastructure investment, and emergency response. These obligations are enforceable by the Nation through the compact dispute resolution process. Any resident of compact territory who be"}, {"id": "s14-6", "num": "§14.6", "name": "Treaty Supremacy and Continuity", "text": "All treaties entered into by predecessor governments with indigenous nations are binding obligations of the Republic. Treaty rights cannot be diminished by legislation — they must be honored, renegotiated with consent, or formally superseded by mutual agreement through the compact negotiation proces"}, {"id": "s14-7", "num": "§14.7", "name": "Indigenous Nation Status Elections", "text": "An indigenous nation with an established compact under Article XIV holds the constitutional right to initiate a status transition through its own democratic or traditional governance process. Three status options are available: (a) Compact Status — continued Article XIV compact relationship (default"}, {"id": "s14-7-a", "num": "§14.7.a", "name": "Status Election Process", "text": "A status election under §14.7 requires: (1) a decision by the nation's own governance process, meeting the standards the nation itself defines for major governance decisions; and (2) publication of the election to the NRS within 30 days of the governance decision. A status election is irrevocable — "}, {"id": "s15-1", "num": "§15.1", "name": "Two Amendment Paths", "text": "This Constitution may be amended through two paths, both requiring a 2/3 supermajority of the full seated membership of both chambers as the legislative threshold. No executive signature is required; no executive veto applies. Every member's vote on any amendment is published to the NRS. \n\nPath A — "}, {"id": "s15-2", "num": "§15.2", "name": "No Executive Veto; Amendment Takes Effect", "text": "Neither the President nor the PM has any role in the constitutional amendment process. No signature required. No veto available. An amendment takes effect immediately upon LI certification (Path A) or Elections Panel certification (Path B) and NRS publication — no implementation delay, no executive "}, {"id": "s15-5", "num": "§15.5", "name": "Amendment Consistency and Supremacy", "text": "An amendment that is logically inconsistent with an existing provision must either explicitly repeal the inconsistent provision or the inconsistency is treated as void. The LI publishes a consistency analysis of any proposed amendment within 30 days of its official proposal — advisory, but a permane"}, {"id": "s15-6", "num": "§15.6", "name": "Supremacy of This Constitution", "text": "This Constitution is the supreme law of the Federated Republic. All legislative acts, executive orders, treaties, administrative decisions, and government actions must be consistent with this Constitution. Any provision inconsistent with this Constitution is void to the extent of the inconsistency."}, {"id": "s16-1", "num": "§16.1", "name": "Digital Infrastructure Commission", "text": "The Digital Infrastructure Commission is a constitutionally independent body responsible for operating the National Record System, the National Voting System, and maintaining all constitutional candidate registries and pools as the administrative keeper of record. The Commission comprises two panels"}, {"id": "s16-1-a", "num": "§16.1.a", "name": "DIC Administrator Appointment and Terms", "text": "The PM nominates DIC administrators from the DIC Administrator Pool maintained by the Elections Panel. The Senate confirms by 2/3 supermajority. Administrators serve a primary 8-year non-renewable term. The PM may grant a single 2-year extension to any administrator before their term expires where a"}, {"id": "s16-1-c", "num": "§16.1.c", "name": "Removal and Accountability", "text": "For-cause removal of any DIC administrator requires: a substantiated finding from a State Designee Panel under §8.9; a 14-day SC appeal window from publication of the finding; and a 2/3 vote of both chambers simultaneously. Duty suspension triggers upon publication of a substantiated Panel finding. "}, {"id": "s16-3", "num": "§16.3", "name": "NVS Properties and Voting Rights", "text": "The National Voting System must maintain three constitutionally required properties simultaneously: ballot secrecy (technically impossible to link any vote to any voter, including in post-election audits), public auditability (aggregate results mathematically verifiable by anyone with NRS access; ev"}, {"id": "s16-5", "num": "§16.5", "name": "DIC Accountability and Emergency Authority", "text": "Where a panel administrator seat becomes vacant mid-term, the PM nominates a replacement within 60 days and the Senate confirms within 90 days of the vacancy opening; failure to confirm within that period is a constitutional compliance breach. The replacement serves the remainder of the vacated term"}, {"id": "s17-1", "num": "§17.1", "name": "The Use Doctrine", "text": "Federal government holds no territorial sovereignty within any State or Territory. All federal property rights are functional use rights — operational control over a designated footprint for the duration of the stated function. Use rights do not constitute ownership, do not transfer sovereignty from"}, {"id": "s17-2", "num": "§17.2", "name": "Seat of Government", "text": "The Republic holds no territorial sovereignty at its Seat of Government. The Seat is hosted by a State or Territory selected through a competitive bid process. The PM publishes a Requirements Specification to the NRS defining minimum functional, security, physical, and operational requirements; the "}, {"id": "s17-3", "num": "§17.3", "name": "Operational Use Rights", "text": "When a federal function ends, the Operational Use Right terminates automatically; the federal government must publish notice of termination to the NRS within the period defined by statute. The land and all improvements revert to the host State automatically unless the federal government and host Sta"}, {"id": "s17-4", "num": "§17.4", "name": "The National Trust", "text": "The National Trust holds all federal land not conveyed by statute to States, indigenous compact territories, or private parties. Land disposal requires statute — the executive cannot convey or encumber public land unilaterally. National Trust designation requires a 2/3 vote of both chambers with hos"}, {"id": "s17-5", "num": "§17.5", "name": "Federal Property in Territories", "text": "Federal operational use rights in Territories follow the same framework as in States under §17.3 and §17.4. Host State legislative consent is not required because Territories have no State legislature; the Territory's representative body and the LI are consulted before any use right is registered."}, {"id": "s18-1", "num": "§18.1", "name": "Electoral Finance", "text": "Electoral finance is regulated to prevent structural distortion of democratic accountability through concentrated financial influence. All contributions above the de minimis threshold must be publicly disclosed to the Elections Panel and published to the NRS — anonymity in electoral finance is prohi"}, {"id": "s18-2", "num": "§18.2", "name": "Campaign Conduct", "text": "Candidates for constitutional office campaign in compliance with published Elections Panel conduct standards: prohibition on demonstrably false statements of material fact about a candidate's recorded votes; prohibition on impersonating other candidates; prohibition on vote suppression activities; a"}, {"id": "s18-3", "num": "§18.3", "name": "Public Campaign Financing", "text": "The Republic maintains a publicly funded campaign financing system as an alternative to private fundraising. The system provides all registered candidates with equal baseline funding; no allocation may advantage incumbents or established parties. Candidates who accept public financing are subject to"}, {"id": "s19-1", "num": "§19.1", "name": "Activation Threshold and Ratification", "text": "This constitution takes effect upon: (1) interim Elections Panel certification that the NVS is operational and meets §16.3; and (2) a national ratification vote achieving 60% affirmative support with at least 50% participation. Ratification creates binding constitutional obligations on all governmen"}, {"id": "s19-2", "num": "§19.2", "name": "Day Zero and Transition", "text": "Day Zero is the date the ratification threshold is certified as achieved. Upon ratification: all laws conflicting with the Individual Sovereignty Floor are immediately null and void; all public assets transfer to the NRS; and the 24-month Transition Window begins. The Republic exists the moment the "}, {"id": "s19-4", "num": "§19.4", "name": "Caretaker Status", "text": "All existing government officials serve as caretakers during the Transition Window — restricted to maintaining existing services only; no new permanent legislation. Transition is supervised by a joint Inspectorate panel of one representative per Inspectorate appointed by their respective IGs; the pa"}, {"id": "s19-5", "num": "§19.5", "name": "Pre-Constitutional Classified Documents", "text": "The Legislature must establish a Classification Review Commission within 90 days of Phase 4 activation. The Commission applies constitutional classification criteria to predecessor classified material: legitimately classified material enters the standard classification framework from Day Zero; impro"}, {"id": "s19-6", "num": "§19.6", "name": "Pre-Existing Obligations", "text": "The Republic assumes the public debt obligations of its predecessor government as a constitutional matter — it does not inherit a clean slate. Active military operations of the prior government continue under existing authorization until the §2.2 tier framework can apply; the President, once inaugur"}, {"id": "s19-7", "num": "§19.7", "name": "Transition Territories", "text": "Territories or subdivisions meeting the Statehood Audit Competency Baseline by Phase 2 end may petition to enter as State or Territory. Those failing the Baseline enter as Territory and may begin the Statehood Audit immediately. Any territory may choose Territory status by simple legislative vote re"}, {"id": "s19-8", "num": "§19.8", "name": "Transition Candidate Registers", "text": "The joint Inspectorate panel assembles the initial Candidate Registers for all constitutionally established positions before Phase 3 elections can occur. The panel performs the register-assembly and vetting function that permanent Inspectorates will assume after Phase 4; registers assembled by the p"}, {"id": "s19-9", "num": "§19.9", "name": "Transitional Accountability Mechanism", "text": "Where a ratifying polity's predecessor government has documented constitutional violations — systematic rights abuses, documented atrocities — the Republic may establish a Transitional Accountability Mechanism by statute passed by 2/3 of both chambers. The TAM is time-limited, non-criminal (it canno"}, {"id": "s19-10", "num": "§19.10", "name": "Required Statutory Agency Establishment", "text": "Where this Constitution assigns a specific function to a statutory independent agency under §3.9, the Legislature shall establish that agency within the following timeframes from Phase 4 activation: the CLT Administrator under §5.1.c, within 180 days; the Census Bureau under §3.2, within 18 months. "}, {"id": "s20-1", "num": "§20.1", "name": "Associated Community Status", "text": "Exclusively for sovereign entities — not a form of State or Territory status, not transitional, not incorporation. Available to nations that have completed the independence process under §13.7, to independent nations outside the Republic seeking a defined relationship, or to nations recognised as pr"}, {"id": "s20-2", "num": "§20.2", "name": "Compact Terms and Equal Sovereignty", "text": "Equal parties; neither constitutionally superior. Observing delegates attend House and Senate proceedings relevant to the compact — speaking rights, no vote, no quorum or threshold effect. The Republic may not impose its constitutional governance architecture on an Associated Community as a conditio"}, {"id": "s20-3", "num": "§20.3", "name": "Compact Conditions and Compliance", "text": "No compact may be entered or ratified with any entity whose governance practices include, authorise, or systematically permit violations of any of the non-derogable rights established in §1.26.b, committed against any person within its jurisdiction. The Judicial Inspectorate certifies compliance wit"}, {"id": "s20-4", "num": "§20.4", "name": "Sovereign Mobility", "text": "The Associated Community may at any time, by its own democratic or traditional governance process, elect to terminate the compact and proceed as a fully independent sovereign nation. No Republic consent is required for compact termination, and the Republic may not impose conditions on or penalties f"}, {"id": "s20-5", "num": "§20.5", "name": "Reciprocal Obligations and Review", "text": "The compact must specify with particularity the reciprocal obligations of both parties and the review mechanism. The Associated Community holds obligations to the Republic as well as rights from it. Review must be scheduled at regular intervals defined in the compact; either party may request a revi"}, {"id": "s20-6", "num": "§20.6", "name": "Compact Ratification", "text": "A compact with an Associated Community requires Senate ratification by 2/3 of full seated membership, consistent with the treaty ratification threshold under §3.6. Both executives must transmit the proposed compact to the Senate simultaneously with a joint assessment of its consistency with this Art"}, {"id": "s20-7", "num": "§20.7", "name": "Compact Continuity", "text": "Compacts in force at the time of any government transition continue without interruption and bind successive governments of the Republic. No election result, change in the Republic's internal constitutional arrangements, or government transition affects the validity or standing of a compact in force"}, {"id": "s2-14-a", "num": "§2.14.a", "name": "Coordination Failure Protocol", "text": "Where both executives are acting within their respective domains but their actions are materially incompatible — creating an operational deadlock not resolvable as a domain dispute under §2.4 or an emergency under §2.14 — either executive may declare"}, {"id": "s3-9-a", "num": "§3.9.a", "name": "Independent Officer Removal — Judicial Track", "text": "Where two of the three Inspectorates jointly certify for-cause grounds and petition the SC, the SC determines within 30 days whether the certified grounds constitute sufficient cause for suspension. If cause is found, the officer is suspended and the"}, {"id": "s4-3-a", "num": "§4.3.a", "name": "Supreme Court Quorum", "text": "A majority of the SC's seated justices — including any Temporary Associate Justices — constitutes quorum for ordinary decisions. Constitutional questions require a minimum of five justices regardless of total seated membership."}, {"id": "s4-4-a", "num": "§4.4.a", "name": "Senate Bypass — Public Confirmation", "text": "Where the LI has certified a Senate breach under §4.4, the PM may — with 2/3 House consent — place the serving Temporary Associate Justice on the next federal electoral period ballot for public confirmation. Confirmation requires 60% of votes cast."}, {"id": "s8-1-d", "num": "§8.1.d", "name": "IG Term Expiry and Incapacity", "text": "An IG's constitutional authority terminates automatically at the moment their term expires — no further act or proceeding is required. Any official act taken after term expiry is constitutionally void."}, {"id": "s8-12-a", "num": "§8.12.a", "name": "Institutional Compromise Protocol", "text": "Where two of the three Inspectorates jointly certify that the third is operating in demonstrable bad faith, they petition the SC directly for confirmation of the finding; the SC rules within 14 days."}, {"id": "s8-14", "num": "§8.14", "name": "Registry Integrity Standards", "text": "These standards apply to all registries and candidate pools maintained under constitutional mandate. Eligibility criteria are strictly objective. No registry administrator may apply criteria relating to legal philosophy, judicial temperament, ideolog"}, {"id": "s9-5", "num": "§9.5", "name": "Classification Criteria", "text": "Government records may be classified only on grounds the Legislature defines by statute. Classification to conceal a constitutional violation, policy disagreement, or political embarrassment is prohibited."}, {"id": "s9-5-a", "num": "§9.5.a", "name": "Duration Framework", "text": "No record may remain classified beyond 25 years from the date of original classification. A single 5-year extension may be granted where the responsible executive publishes a justification to the EI."}, {"id": "s1-31", "num": "§1.31", "name": "Continuity of Constitutionally Mandated Offices", "text": "For every office established by this Constitution with a fixed term, the confirmed or elected successor's term begins at the precise moment the incumbent's term concludes — no gap exists between the end of one term and the commencement of the next."}, {"id": "s8-15", "num": "§8.15", "name": "Constitutional Officer Removal Framework", "text": "Governs for-cause removal of all constitutionally confirmed independent officers. Standard Track: State Designee Panel + 2/3 both chambers. Judicial Track: Two Inspectorates + SC + Senate 3/5 or public election at 60%."}, {"id": "s11-4", "num": "§11.4", "name": "Electoral Supermajority Threshold", "text": "60% of votes cast is the constitutional threshold for all direct electoral supermajority determinations — presidential first-round (§7.2), SC public confirmation (§4.4.a), public election removal (§8.15)."}];
